import os
import tarfile


def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        with tarfile.open(tar_path) as tar:
            for member in tar.getmembers():
                dest_path_abs = os.path.abspath(dest_path)
                member_full_path = os.path.join(dest_path_abs, member.path)
                dest_path_norm = os.path.normpath(dest_path_abs)
                member_full_norm = os.path.normpath(member_full_path)
                if os.path.commonpath([dest_path_norm, member_full_norm]) != dest_path_norm:
                    return False
            tar.extractall(path=dest_path)
        return True
    except Exception:
        return False

from typing import Dict

def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    mapping = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }
    if info_type not in mapping:
        return header
    try:
        new_header = header.copy()
        new_header[mapping[info_type]] = info_content
        return new_header
    except:
        return header

