class SafeNodeVisitor(ast.NodeVisitor):
    def visit(self, node):
        allowed_types = {
            ast.Expression, ast.Num, ast.BinOp, ast.UnaryOp, ast.operator,
            ast.cmpop, ast.Name, ast.Load, ast.Call, ast.keyword, ast.Attribute
        }
        if not isinstance(node, allowed_types):
            raise ValueError("Invalid syntax")
        return super().visit(node)

