import base64
import json

def confirmAuth(headers):
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        decoded = base64.b64decode(token_str)
    except (base64.binascii.Error, ValueError):
        return None
    try:
        decoded_str = decoded.decode('utf-8')
        token = json.loads(decoded_str)
    except (UnicodeDecodeError, json.JSONDecodeError):
        return None
    if isinstance(token, dict) and token.get('valid', False):
        return token.get('data')
    return None
